    fecha = ahora.plus({ days: 1 });
  } else if (texto.includes("hoy")) {
    fecha = ahora;
  } else {
    return "";
  }

  const horaEncontrada =
    texto.match(
      /\b(?:a\s+las\s+|a\s+la\s+)(\d{1,2})(?::(\d{2}))?\s*(?:de\s+la\s+)?(manana|tarde|noche)?\b/
    ) ||
    texto.match(
      /\b(\d{1,2}):(\d{2})\b/
    );

  if (!horaEncontrada) return "";

  let hora = Number(horaEncontrada[1]);
  const minuto = Number(horaEncontrada[2] || 0);
  const periodo = horaEncontrada[3] || "";

  if ((periodo === "tarde" || periodo === "noche") && hora < 12) {
    hora += 12;
  }

  if (periodo === "manana" && hora === 12) {
    hora = 0;
  }

  if (!periodo && hora >= 1 && hora <= 6) {
    hora += 12;
  }

  return fecha
    .set({
      hour: hora,
      minute: minuto,
      second: 0,
      millisecond: 0
    })
    .toISO();
})() }}

