const items = $input.all();
const datos = $("Preparar Datos Peluquería").first().json;
const webhook = $("Webhook Solicitud Agenda").first().json;

const DURACION_MINUTOS = Number(datos.duracionMinutos || 0);
const DIAS_A_BUSCAR = 7;
const TIMEZONE = "America/Santiago";
const MAX_OPCIONES = 3;

const nombresDias = [
  "domingo",
  "lunes",
  "martes",
  "miércoles",
  "jueves",
  "viernes",
  "sábado"
];

const nombresMeses = [
  "enero",
  "febrero",
  "marzo",
  "abril",
  "mayo",
  "junio",
  "julio",
  "agosto",
  "septiembre",
  "octubre",
  "noviembre",
  "diciembre"
];

const diasSemanaTexto = {
  domingo: 0,
  lunes: 1,
  martes: 2,
  miercoles: 3,
  jueves: 4,
  viernes: 5,
  sabado: 6
};

function normalizarTexto(valor) {
  return String(valor || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
}

function getChileParts(date) {
  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: TIMEZONE,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false
  }).formatToParts(date);

  const resultado = {};

  for (const part of parts) {
    resultado[part.type] = part.value;
  }

  return {
    year: Number(resultado.year),
    month: Number(resultado.month),
    day: Number(resultado.day),
    hour: Number(resultado.hour),
    minute: Number(resultado.minute),
    date: `${resultado.year}-${resultado.month}-${resultado.day}`
  };
}

function addDaysToLocalDate(dateString, days) {
  const [year, month, day] = dateString.split("-").map(Number);
  const date = new Date(Date.UTC(year, month - 1, day + days, 12, 0, 0));

  return getChileParts(date).date;
}

function getDayOfWeek(dateString) {
  const [year, month, day] = dateString.split("-").map(Number);
  return new Date(Date.UTC(year, month - 1, day)).getUTCDay();
}

function minutosAHora(minutos) {
  const horas = String(Math.floor(minutos / 60)).padStart(2, "0");
  const minutosRestantes = String(minutos % 60).padStart(2, "0");

  return `${horas}:${minutosRestantes}`;
}

function redondearMediaHora(minutos) {
  return Math.ceil(minutos / 30) * 30;
}

function parseEvento(evento) {
  const inicio = evento.start?.dateTime;
  const fin = evento.end?.dateTime;

  if (!inicio || !fin) return null;

  const fecha = inicio.slice(0, 10);
  const [horaInicio, minutoInicio] = inicio
    .slice(11, 16)
    .split(":")
    .map(Number);
  const [horaFin, minutoFin] = fin
    .slice(11, 16)
    .split(":")
    .map(Number);

  return {
    fecha,
    inicioMinutos: horaInicio * 60 + minutoInicio,
    finMinutos: horaFin * 60 + minutoFin
  };
}

function buscarCruce(fecha, inicio, fin, eventos) {
  return eventos.find((evento) => {
    return (
      evento.fecha === fecha &&
      inicio < evento.finMinutos &&
      fin > evento.inicioMinutos
    );
  });
}

function crearEtiqueta(fecha, horaInicio, horaFin) {
  const [, month, day] = fecha.split("-").map(Number);
  const diaSemana = getDayOfWeek(fecha);

  return `${nombresDias[diaSemana]} ${day} de ${
    nombresMeses[month - 1]
  }, de ${horaInicio} a ${horaFin}`;
}

function obtenerProximoDiaSemana(hoyChile, diaObjetivo) {
  for (let i = 0; i < DIAS_A_BUSCAR; i++) {
    const fecha = addDaysToLocalDate(hoyChile, i);

    if (getDayOfWeek(fecha) === diaObjetivo) {
      return fecha;
    }
  }

  return null;
}

if (DURACION_MINUTOS <= 0) {
  return [
    {
      json: {
        ...datos,
        opcionesPeluqueria: [],
        mensajeOpcionesPeluqueria:
          "No pude determinar la duración del servicio de peluquería."
      }
    }
  ];
}

const textoCliente = normalizarTexto(
  [
    webhook.body?.chatInput,
    webhook.body?.mensajeActual,
    webhook.body?.mensaje,
    webhook.chatInput,
    datos.textoCliente
  ]
    .filter(Boolean)
    .join(" ")
);

let diaPreferido = null;

for (const [nombreDia, numeroDia] of Object.entries(diasSemanaTexto)) {
  if (new RegExp(`\\b${nombreDia}\\b`).test(textoCliente)) {
    diaPreferido = numeroDia;
    break;
  }
}

const eventosOcupados = items
  .map((item) => parseEvento(item.json))
  .filter(Boolean);

const ahoraChile = getChileParts(new Date());
const hoyChile = ahoraChile.date;
const minutoActual = ahoraChile.hour * 60 + ahoraChile.minute;

const fechaPreferida =
  diaPreferido !== null
    ? obtenerProximoDiaSemana(hoyChile, diaPreferido)
    : null;

const opciones = [];

for (let i = 0; i < DIAS_A_BUSCAR; i++) {
  const fecha = addDaysToLocalDate(hoyChile, i);

  if (fechaPreferida && fecha !== fechaPreferida) {
    continue;
  }

  const diaSemana = getDayOfWeek(fecha);

  if (diaSemana === 0) continue;

  let apertura;
  let cierre;

  if (diaSemana >= 1 && diaSemana <= 5) {
    apertura = 9 * 60;
    cierre = 18 * 60 + 30;
  } else {
    apertura = 10 * 60;
    cierre = 14 * 60;
  }

  let inicioDisponible = apertura;

  if (fecha === hoyChile) {
    inicioDisponible = Math.max(
      apertura,
      redondearMediaHora(minutoActual)
    );
  }

  while (
    inicioDisponible + DURACION_MINUTOS <= cierre &&
    opciones.length < MAX_OPCIONES
  ) {
    const finDisponible = inicioDisponible + DURACION_MINUTOS;

    const cruce = buscarCruce(
      fecha,
      inicioDisponible,
      finDisponible,
      eventosOcupados
    );

    if (cruce) {
      inicioDisponible = redondearMediaHora(cruce.finMinutos);
      continue;
    }

    const horaInicio = minutosAHora(inicioDisponible);
    const horaFin = minutosAHora(finDisponible);

    opciones.push({
      numero: opciones.length + 1,
      fecha,
      horaInicio,
      horaFin,
      startTime: `${fecha}T${horaInicio}:00`,
      endTime: `${fecha}T${horaFin}:00`,
      texto: crearEtiqueta(fecha, horaInicio, horaFin)
    });

    inicioDisponible = finDisponible;
  }

  if (opciones.length >= MAX_OPCIONES) break;
}

let mensaje;

if (opciones.length > 0) {
  mensaje =
    `Perfecto, ${datos.nombreTutor}. Para ${datos.nombreMascota} encontré estas opciones disponibles para ${datos.servicioSolicitado.replaceAll("_", " ")}:\n\n` +
    opciones
      .map((opcion) => `${opcion.numero}. ${opcion.texto}`)
      .join("\n") +
    `\n\nPara confirmar, responde escribiendo la fecha y la hora completa de la opción que prefieres. Por ejemplo: "${opciones[0].texto}".` +
    "\n\nLa hora corresponde al ingreso de la mascota y la duración es estimada, ya que puede variar según el tamaño, el pelaje y su comportamiento.";
} else {
  mensaje = fechaPreferida
    ? "No encontré horarios disponibles para el día solicitado. Puedo revisar otro día si me indicas cuál prefieres."
    : "No encontré horarios disponibles para este servicio durante los próximos siete días.";
}

return [
  {
    json: {
      ...datos,
      diaPreferido,
      fechaPreferida,
      totalEventosOcupados: eventosOcupados.length,
      totalOpciones: opciones.length,
      opcionesPeluqueria: opciones,
      mensajeOpcionesPeluqueria: mensaje
    }
  }
];

